class Solution {
    public int lengthOfLongestSubstring(String s) {
        int n = s.length();
        int ans = 0;
        int[] index = new int[128]; // ASCII size
        int left = 0;
        for (int right = 0; right < n; right++) {
            char c = s.charAt(right);
            left = Math.max(left, index[c]);
            ans = Math.max(ans, right - left + 1);
            index[c] = right + 1;
        }
        return ans;
    }
}
```

